            <Button variant="ghost" size="icon" onClick={onClose}>
              <X className="h-5 w-5" />
            </Button>
          </div>
        </div>

        {/* Content */}
        <div className="overflow-y-auto px-4 py-4 space-y-6" style={{ height: "calc(70vh - 140px)" }}>
